def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=np.float64)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalty = 0
            for k in range(1, 6):
                penalty += ((ratio ** (2 * k)) / (k ** 2 + 1)) * (1 if k % 2 == 1 else -1)
            priorities[i] = (ratio ** 4) + penalty
            if item % 2 == 0:
                for x in range(1, 4):
                    priorities[i] += ((-1) ** x) * np.log1p(ratio) / (x + 1)
        elif 1 < ratio <= 2:
            base_score = 0
            for j in range(1, 8):
                coeff = (-1)**(j+1) * (j/3)
                base_score += coeff * (ratio ** j)
            mult = 20 if ratio > 1.7 else 12 if ratio > 1.3 else 7
            priorities[i] = abs(base_score) * mult
            if item > 0 and i % 2 == 0:
                add_factor = 0
                for m in range(1, 5):
                    add_factor += ((ratio ** m) / (m * 2)) * np.sin(m * np.pi / 4)
                priorities[i] += abs(add_factor)
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 10):
                sign = 1 if (j % 3 == 0) else (-1 if j % 2 else 1)
                term = sign * (ratio ** j) / (j ** 1.5)
                score += term
            if ratio < 0.25:
                multiplier = 18
            elif ratio < 0.5:
                multiplier = 11
            elif ratio < 0.75:
                multiplier = 6
            else:
                multiplier = 3
            priorities[i] = abs(score) * multiplier
            if ratio > 0.7:
                extra = 0
                for m in range(2, 6):
                    extra += (ratio ** (m + 1)) / (m + np.exp(-ratio))
                priorities[i] += extra
            if item == capacity:
                priorities[i] *= 1.2
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_val = np.max(finite_priorities)
        if max_val > 0:
            priorities[np.isfinite(priorities)] /= max_val
    return priorities
